import React, { useEffect, useState } from "react";

const UploadBills = ({ employee }) => {
  const [files, setFiles] = useState([]);
  const [billList, setBillList] = useState([]);

  useEffect(() => {
    if (employee?.empId || employee?.empld) fetchBills();
  }, [employee]);

  const fetchBills = async () => {
    try {
      const empId = employee.empId || employee.empld;
      const res = await fetch(
        `https://prasa-app-yde3.onrender.com/bills?empId=${empId}`
      );
      const data = await res.json();
      setBillList(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error(err);
      setBillList([]);
    }
  };

  const uploadBills = async () => {
    if (!files.length) return alert("Select files first!");

    const form = new FormData();
    const empId = employee.empId || employee.empld;

    form.append("empId", empId);

    for (let f of files) form.append("bills", f);

    await fetch("https://prasa-app-yde3.onrender.com/upload-bills", {
      method: "POST",
      body: form,
    });

    alert("Bills uploaded successfully!");
    fetchBills();
  };

  const deleteBill = async (id) => {
    await fetch(`https://prasa-app-yde3.onrender.com/delete-bill/${id}`, {
      method: "DELETE",
    });

    fetchBills();
  };

  const downloadReport = () => {
    alert("Downloading Monthly Bills Report…");
  };

  return (
    <div style={page}>
      <div style={headerCard}>
        <button onClick={() => window.history.back()} style={backBtn}>←</button>
        <h2 style={headerTitle}>Upload Bills</h2>
        <p style={empInfo}>{employee.empName} • {employee.empId}</p>
      </div>

      {/* UPLOAD CARD */}
      <div style={uploadCard}>
        <input
          type="file"
          multiple
          onChange={(e) => setFiles([...e.target.files])}
          style={fileInput}
        />
        <button style={uploadBtn} onClick={uploadBills}>
          Upload Bills
        </button>
      </div>

      {/* BILLS TABLE */}
      <table style={table}>
        <thead>
          <tr>
            <th>Date</th>
            <th>File Name</th>
            <th>Preview</th>
            <th>Delete</th>
          </tr>
        </thead>

        <tbody>
          {billList.length === 0 ? (
            <tr><td colSpan="4" style={emptyText}>No bills uploaded</td></tr>
          ) : (
            billList.map((b) => (
              <tr key={b.id}>
                <td>{b.uploaded_at?.substring(0,10)}</td>
                <td>{b.file_name}</td>
                <td>
                  <a href={b.file_path} target="_blank" rel="noreferrer">
                    View
                  </a>
                </td>
                <td>
                  <button style={deleteBtn} onClick={() => deleteBill(b.id)}>Delete</button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>

      {/* DOWNLOAD REPORT BUTTON */}
      <div style={downloadContainer}>
        <button style={downloadBtn} onClick={downloadReport}>
          📄 Download Monthly Bills Report
        </button>
      </div>
    </div>
  );
};

export default UploadBills;

/* UI STYLES */
const green = "#0F9D58";

const page = { padding: 20, background: "#F1F8F2", minHeight: "100vh" };
const headerCard = { background:"#fff",padding:18,borderRadius:15,boxShadow:"0 3px 10px rgba(0,0,0,0.1)",marginBottom:15 };
const backBtn = { background:"#fff",border:`1px solid ${green}`,color:green,borderRadius:10,padding:"6px 12px",fontSize:20,cursor:"pointer" };
const headerTitle = { fontSize:24, fontWeight:"700", color:green };
const empInfo = { color:"#666", marginTop:-5, fontSize:14 };

const uploadCard = { background:"#E8F5E9", padding:20, borderRadius:12, marginBottom:20 };
const fileInput = { padding:10, background:"#fff", borderRadius:10, width:"100%" };

const uploadBtn = {
  background:green, color:"#fff", border:"none",
  marginTop:12, padding:"10px 18px",
  borderRadius:10, cursor:"pointer", fontSize:16
};

const table = {
  width:"100%", background:"white",
  borderRadius:14, padding:10,
  boxShadow:"0 2px 8px rgba(0,0,0,0.08)"
};

const deleteBtn = {
  background:"red", color:"#fff",
  padding:"6px 12px", borderRadius:8,
  border:"none", cursor:"pointer"
};

const emptyText = { textAlign:"center", padding:20, color:"#999" };

const downloadContainer = { marginTop:20, textAlign:"left" };

const downloadBtn = {
  background:green, color:"white", padding:"12px 20px",
  borderRadius:10, border:"none", cursor:"pointer",
  fontSize:16, fontWeight:"600"
};
